# BEST PRACTICE: Warm-up + Gradient Clipping + Checkpoint Averaging
import torch
from torch.optim.lr_scheduler import LambdaLR

class CricketLLMTrainer:
    def __init__(self, model, initial_lr=1e-4, warmup_steps=1000):
        self.model = model
        self.optimizer = torch.optim.AdamW(model.parameters(), lr=initial_lr)
        self.warmup_steps = warmup_steps
        self.batsman_scores = []  # Track validation losses
        self.checkpoints = []

        # Warm-up scheduler: gradual LR increase
        def wicket_keeper_warmup(step):
            if step < warmup_steps:
                return float(step) / float(max(1, warmup_steps))
            return 1.0

        self.scheduler = LambdaLR(self.optimizer, wicket_keeper_warmup)

    def training_step(self, batch_loss):
        batch_loss.backward()

        # BEST: Gradient clipping (prevent boundary sixes)
        torch.nn.utils.clip_grad_norm_(self.model.parameters(), max_norm=1.0)

        self.optimizer.step()
        self.scheduler.step()
        self.optimizer.zero_grad()

    def validation_step(self, val_loss):
        self.batsman_scores.append(val_loss)
        # Save top 5 checkpoints (cricket team selection)
        if len(self.batsman_scores) <= 5 or val_loss < max(self.batsman_scores[:-1]):
            self.checkpoints.append(self.model.state_dict())
            if len(self.checkpoints) > 5:
                self.checkpoints.pop(0)

    def get_averaged_weights(self):
        # BEST: Checkpoint averaging (XI selection strategy)
        avg_state = {}
        for key in self.checkpoints[0].keys():
            avg_state[key] = torch.stack(
                [ckpt[key] for ckpt in self.checkpoints]
            ).mean(dim=0)
        return avg_state

# ANTI-PATTERN: No warm-up, unbounded gradients, single checkpoint
class BadCricketTrainer:
    def __init__(self, model):
        self.model = model
        self.optimizer = torch.optim.SGD(model.parameters(), lr=0.1)  # Too high!
        self.best_checkpoint = None
        self.best_loss = float('inf')

    def training_step(self, batch_loss):
        batch_loss.backward()
        # ANTI-PATTERN: No gradient clipping (sixer after sixer!)
        self.optimizer.step()  # Gradients can explode
        self.optimizer.zero_grad()

    def validation_step(self, val_loss):
        # ANTI-PATTERN: Keep only single best (fragile selection)
        if val_loss < self.best_loss:
            self.best_loss = val_loss
            self.best_checkpoint = self.model.state_dict()
